<template><div class="page"><div class="toolbar"><h2>声音管理</h2><el-button type="primary" @click="dialog=true">上传声音</el-button><el-button @click="load">刷新</el-button></div><el-table class="card" :data="list" v-loading="loading" empty-text="暂无声音模型"><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="name" label="名称"/><el-table-column prop="description" label="描述"/><el-table-column prop="status" label="状态"><template #default="s"><el-tag :type="s.row.status==='就绪'?'success':s.row.status==='失败'?'danger':'warning'">{{s.row.status}}</el-tag></template></el-table-column><el-table-column prop="createdAt" label="创建时间"/><el-table-column label="操作" width="220"><template #default="s"><el-button size="small" @click="train(s.row)">训练</el-button><el-button size="small" type="danger" @click="remove(s.row.id)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="dialog" title="上传音频" width="520px"><el-form :model="form" label-width="80px"><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="描述"><el-input v-model="form.description" type="textarea"/></el-form-item><el-form-item label="文件"><el-upload :auto-upload="false" :limit="1" :on-change="f=>file=f.raw" accept=".wav,.mp3,.m4a"><el-button>选择音频</el-button><template #tip><div class="muted">支持 wav / mp3 / m4a</div></template></el-upload></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="uploading" @click="submitUpload">上传并训练</el-button></template></el-dialog></div></template>
<script setup>import { ref,reactive,onMounted } from 'vue';import { ElMessage,ElMessageBox } from 'element-plus';import { getVoiceList,uploadAudio,startVoiceTrain,deleteVoice } from '../api/voice';const list=ref([]),loading=ref(false),dialog=ref(false),uploading=ref(false),file=ref(null);const form=reactive({name:'',description:''});async function load(){loading.value=true;try{list.value=await getVoiceList()||[]}finally{loading.value=false}}async function submitUpload(){if(!form.name||!file.value)return ElMessage.warning('请填写名称并选择音频');const fd=new FormData();fd.append('file',file.value);fd.append('name',form.name);fd.append('description',form.description||'');uploading.value=true;try{const voice=await uploadAudio(fd);await startVoiceTrain(voice.id);ElMessage.success('上传成功，已提交训练');dialog.value=false;form.name='';form.description='';file.value=null;load()}finally{uploading.value=false}}async function train(row){await startVoiceTrain(row.id);ElMessage.success('已提交训练任务');load()}async function remove(id){await ElMessageBox.confirm('确认删除该声音模型？','提示');await deleteVoice(id);ElMessage.success('删除成功');load()}onMounted(load)</script>
